#include <bits/stdc++.h>
using namespace std;

int n, s;
int p[100005], c[100005];

int main() {
    cin >> n >> s;
    for (int i = 0; i < n; i++) {
        cin >> p[i] >> c[i];
    }
    long long ans = 0;
    while (true) {
        long long sum = 0;
        bool flag = true;
        for (int i = 0; i < n; i++) {
            if (c[i] > 0) {
                sum += p[i];
                flag = false;
            }
        }
        if (flag) break;
        if (s < sum) {
            ans += s;
        }
        else {
            ans += sum;
        }
        for (int i = 0; i < n; i++) {
            if (c[i] > 0) {
                c[i]--;
            }
        }
    }
    cout << ans;
    return 0;
}
